import org.owasp.esapi.ESAPI;
import org.owasp.esapi.codecs.HTMLEntityCodec;

public class SecureXSSExample {

    public static void main(String[] args) {
        // Simulating user input from a form
        String userInput = "<script>alert('XSS attack!')</script>";

        // Encoding user input to prevent XSS attacks
        HTMLEntityCodec codec = new HTMLEntityCodec();
        String encodedInput = codec.encodeForHTML(userInput);

        // Properly handling user input by encoding it before outputting to a web page
        String output = "<p>User input: " + encodedInput + "</p>";

        // Outputting the result to the console (simulating displaying it on a webpage)
        System.out.println(output);
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
